// ── REVEAL ON SCROLL ──
const revEls = document.querySelectorAll('.reveal');
const revObs = new IntersectionObserver(es => es.forEach(e => { if(e.isIntersecting) e.target.classList.add('in'); }), { threshold: 0.1 });
revEls.forEach(el => revObs.observe(el));

// ── CANVAS RESIZE HELPER ──
function resizeCanvas(canvas) {
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  const ctx = canvas.getContext('2d');
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
}

// ══════════════════════════════════════════════════════════════
// HERO FULL-SCREEN PARTICLE FIELD
// ══════════════════════════════════════════════════════════════
(function () {
  const canvas = document.getElementById('hero-particles');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  let W, H;

  function resize() {
    const hero = document.getElementById('hero');
    W = hero.offsetWidth;
    H = hero.offsetHeight;
    canvas.width  = W * dpr;
    canvas.height = H * dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }
  resize();
  window.addEventListener('resize', resize);

  const COUNT = 200;
  const pts = [];

  for (let i = 0; i < COUNT; i++) {
    pts.push({
      x: Math.random() * 1,   // fraction of W — set at draw time
      y: Math.random() * 1,   // fraction of H
      vx: (Math.random() - 0.5) * 0.0003,
      vy: -(Math.random() * 0.0003 + 0.00008),
      r: Math.random() * 1.4 + 0.3,
      baseAlpha: Math.random() * 0.5 + 0.08,
      phase: Math.random() * Math.PI * 2,
      twinkle: Math.random() * 0.025 + 0.008,
    });
  }

  let mx = 0.5, my = 0.5;
  window.addEventListener('mousemove', e => {
    const hero = document.getElementById('hero');
    const rect = hero.getBoundingClientRect();
    mx = (e.clientX - rect.left) / rect.width;
    my = (e.clientY - rect.top)  / rect.height;
  });

  let t = 0;
  function draw() {
    ctx.clearRect(0, 0, W, H);

    // Soft mouse-following glow
    const gx = mx * W, gy = my * H;
    const grad = ctx.createRadialGradient(gx, gy, 0, gx, gy, Math.min(W, H) * 0.6);
    grad.addColorStop(0,   'rgba(40, 90, 220, 0.09)');
    grad.addColorStop(0.6, 'rgba(10, 30, 120, 0.03)');
    grad.addColorStop(1,   'rgba(0,  0,  0,  0)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, W, H);

    // Update + draw particles
    for (let i = 0; i < pts.length; i++) {
      const p = pts[i];
      p.x += p.vx;
      p.y += p.vy;
      if (p.y < -0.02) { p.y = 1.02; p.x = Math.random(); }
      if (p.x < -0.02) p.x = 1.02;
      if (p.x >  1.02) p.x = -0.02;

      const px = p.x * W, py = p.y * H;
      const twinkle = 0.55 + 0.45 * Math.sin(t * p.twinkle * 60 + p.phase);
      ctx.globalAlpha = p.baseAlpha * twinkle;
      ctx.fillStyle = '#ffffff';
      ctx.beginPath();
      ctx.arc(px, py, p.r, 0, Math.PI * 2);
      ctx.fill();
    }

    // Connection lines
    ctx.lineWidth = 0.5;
    for (let i = 0; i < pts.length; i++) {
      for (let j = i + 1; j < pts.length; j++) {
        const dx = (pts[i].x - pts[j].x) * W;
        const dy = (pts[i].y - pts[j].y) * H;
        const d  = Math.sqrt(dx * dx + dy * dy);
        if (d < 80) {
          ctx.globalAlpha = (1 - d / 80) * 0.13;
          ctx.strokeStyle = '#3366ff';
          ctx.beginPath();
          ctx.moveTo(pts[i].x * W, pts[i].y * H);
          ctx.lineTo(pts[j].x * W, pts[j].y * H);
          ctx.stroke();
        }
      }
    }

    ctx.globalAlpha = 1;
    t++;
    requestAnimationFrame(draw);
  }
  draw();
})();

// ── COUNTER ──
function runCounter(el) {
  const target = parseFloat(el.dataset.count);
  const dec = parseInt(el.dataset.dec);
  const dur = 1800;
  const start = performance.now();
  function step(now) {
    const p = Math.min((now - start) / dur, 1);
    const ease = 1 - Math.pow(1 - p, 4);
    const val = ease * target;
    el.textContent = dec === 1 ? val.toFixed(1) + '%' : Math.round(val) + (el.dataset.count === '41' ? '' : el.dataset.count === '3' ? '' : '');
    if(p < 1) requestAnimationFrame(step);
    else el.textContent = dec === 1 ? target.toFixed(1) + '%' : target;
  }
  requestAnimationFrame(step);
}
const ctrObs = new IntersectionObserver(es => es.forEach(e => { if(e.isIntersecting){ runCounter(e.target); ctrObs.unobserve(e.target); } }), { threshold: 0.6 });
document.querySelectorAll('[data-count]').forEach(el => ctrObs.observe(el));

// ══════════════════════════════════════════════════════════════
// THREE.JS HERO - GLB Human Model with Bloom & Interaction
// ══════════════════════════════════════════════════════════════

(async function initHero() {
  // Dynamically import Three.js ES modules
  const THREE = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/build/three.module.js');
  const { GLTFLoader } = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/examples/jsm/loaders/GLTFLoader.js');
  const { EffectComposer } = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/examples/jsm/postprocessing/EffectComposer.js');
  const { RenderPass } = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/examples/jsm/postprocessing/RenderPass.js');
  const { UnrealBloomPass } = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/examples/jsm/postprocessing/UnrealBloomPass.js');
  const { ShaderPass } = await import('https://cdn.jsdelivr.net/npm/three@0.158.0/examples/jsm/postprocessing/ShaderPass.js');

  const canvas = document.getElementById('hero-canvas');
  if (!canvas) return;

  const container = canvas.parentElement;

  function getSize() {
    return { w: container.clientWidth, h: container.clientHeight };
  }

  let { w, h } = getSize();

  // ── RENDERER ──
  const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
  renderer.setSize(w, h);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.2;
  renderer.outputColorSpace = THREE.SRGBColorSpace;

  // ── SCENE ──
  const scene = new THREE.Scene();

  // ── CAMERA ──
  const camera = new THREE.PerspectiveCamera(42, w / h, 0.01, 100);
  camera.position.set(0, 0, 4);

  // ── LIGHTING ──
  // Ambient base
  scene.add(new THREE.AmbientLight(0x112244, 3.0));

  // Key light — cool blue-white from front-top
  const keyLight = new THREE.DirectionalLight(0x99ccff, 4.0);
  keyLight.position.set(2, 6, 4);
  scene.add(keyLight);

  // Fill light — warm purple-pink from side
  const fillLight = new THREE.DirectionalLight(0x6644aa, 2.5);
  fillLight.position.set(-4, 2, 1);
  scene.add(fillLight);

  // Rim light — electric blue from behind
  const rimLight = new THREE.DirectionalLight(0x2266ff, 3.0);
  rimLight.position.set(0, 1, -5);
  scene.add(rimLight);

  // Bottom accent — subtle teal from below
  const bottomLight = new THREE.DirectionalLight(0x004488, 1.5);
  bottomLight.position.set(0, -4, 2);
  scene.add(bottomLight);

  // ── PARTICLES ──
  const particleCount = 320;
  const positions = new Float32Array(particleCount * 3);
  const sizes = new Float32Array(particleCount);
  for (let i = 0; i < particleCount; i++) {
    positions[i * 3]     = (Math.random() - 0.5) * 8;
    positions[i * 3 + 1] = (Math.random() - 0.5) * 8;
    positions[i * 3 + 2] = (Math.random() - 0.5) * 6 - 1;
    sizes[i] = Math.random() * 2.5 + 0.5;
  }
  const pGeo = new THREE.BufferGeometry();
  pGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  pGeo.setAttribute('size', new THREE.BufferAttribute(sizes, 1));
  const pMat = new THREE.PointsMaterial({
    color: 0xffffff, size: 0.035, transparent: true,
    opacity: 0.55, sizeAttenuation: true, depthWrite: false,
    blending: THREE.AdditiveBlending
  });
  scene.add(new THREE.Points(pGeo, pMat));

  // ── SENSOR SPHERES (will be repositioned after model loads) ──
  const sensorMat = new THREE.MeshBasicMaterial({ 
    color: 0xff0000,
    transparent: true,
    opacity: 1
  });
  const sensorGeo = new THREE.SphereGeometry(0.04, 8, 8);
  const sensors = [null, null, null, null].map(() => {
    const m = new THREE.Mesh(sensorGeo, sensorMat.clone());
    m.visible = true;
    // Don't add to scene yet - will add to model when loaded
    return m;
  });

  // Sensor pulse rings
  const ringGeo = new THREE.RingGeometry(0.085, 0.09, 32);
  const rings = sensors.map(() => {
    const m = new THREE.Mesh(ringGeo, new THREE.MeshBasicMaterial({
      color: 0xff0000, transparent: true, opacity: 0.7,
      side: THREE.DoubleSide, depthWrite: false, blending: THREE.AdditiveBlending
    }));
    m.visible = true;
    // Don't add to scene yet - will add to model when loaded
    return m;
  });

  // ── GROUND GRID ──
  const gridHelper = new THREE.GridHelper(6, 20, 0x1133aa, 0x0a1a44);
  gridHelper.position.y = -2.1;
  gridHelper.material.opacity = 0.35;
  gridHelper.material.transparent = true;
  scene.add(gridHelper);

  // Subtle ground glow plane
  const glowPlane = new THREE.Mesh(
    new THREE.PlaneGeometry(4, 1),
    new THREE.MeshBasicMaterial({
      color: 0x0033ff, transparent: true, opacity: 0.06,
      blending: THREE.AdditiveBlending, depthWrite: false
    })
  );
  glowPlane.rotation.x = -Math.PI / 2;
  glowPlane.position.y = -2.05;
  scene.add(glowPlane);

  // ── POST-PROCESSING ──
  const composer = new EffectComposer(renderer);
  composer.addPass(new RenderPass(scene, camera));

  const bloom = new UnrealBloomPass(new THREE.Vector2(w, h), 0.9, 0.5, 0.15);
  composer.addPass(bloom);

  // ── LOAD GLB MODEL ──
  const loader = new GLTFLoader();

  // Decode embedded base64 GLB
  const b64 = '';
  const binary = atob(b64);
  const buf = new ArrayBuffer(binary.length);
  const view = new Uint8Array(buf);
  for (let i = 0; i < binary.length; i++) view[i] = binary.charCodeAt(i);

  let model = null;
  let modelCenter = new THREE.Vector3();
  let modelHeight = 0;

  loader.parse(buf, '', (gltf) => {
    model = gltf.scene;

    // Auto-fit model
    const box = new THREE.Box3().setFromObject(model);
    const size = box.getSize(new THREE.Vector3());
    const center = box.getCenter(new THREE.Vector3());
    modelHeight = size.y;

    // Scale so model fills ~55% of screen height
    const targetH = 1.8;
    const scale = targetH / size.y;
    model.scale.setScalar(scale);

    // Re-center at origin vertically centered
    box.setFromObject(model);
    box.getCenter(modelCenter);
    model.position.sub(modelCenter);
    model.position.y += 0.02; // align feet to ground level

    // Material upgrade — sleek clinical sci-fi look
    model.traverse((child) => {
      if (child.isMesh) {
        child.castShadow = true;
        const oldMat = child.material;
        child.material = new THREE.MeshStandardMaterial({
          color: new THREE.Color(0xffffff),
          metalness: 0.0,
          roughness: 0.8,
          emissive: new THREE.Color(0xffffff),
          emissiveIntensity: 0.1,
          envMapIntensity: 0.5,
        });
        if (oldMat.map) child.material.map = oldMat.map;
      }
    });

    scene.add(model);

    // Position sensors on key body landmarks (scaled to match model)
    const modelScale = model.scale.x;
    const sensorPositions = [
      new THREE.Vector3( 0.00,  1.67 * modelScale,  0.00),   // Head (Z=0.0)
      new THREE.Vector3( 0.00,  1.01 * modelScale,  0.00),   // Lower back (Z=0.0)
      new THREE.Vector3(-0.12,  0.04 * modelScale,  0.05),   // Left foot
      new THREE.Vector3( 0.12,  0.04 * modelScale,  0.05),   // Right foot
    ];
    sensors.forEach((s, i) => {
      s.position.copy(sensorPositions[i]);
      s.visible = true;
      model.add(s);
      rings[i].position.copy(sensorPositions[i]);
      rings[i].visible = true;
      model.add(rings[i]);
    });

  }, (err) => {
    console.error('GLB parse error:', err);
  });

  // ── INTERACTION ──
  let mouseX = 0;
  let targetRotY = 0;
  let currentRotY = 0;
  let isDragging = false;
  let lastMX = 0;

  canvas.addEventListener('mousedown', (e) => { isDragging = true; lastMX = e.clientX; });
  window.addEventListener('mouseup', () => { isDragging = false; });
  canvas.addEventListener('mousemove', (e) => {
    const r = canvas.getBoundingClientRect();
    mouseX = ((e.clientX - r.left) / r.width - 0.5);
    if (isDragging) {
      targetRotY += (e.clientX - lastMX) * 0.008;
      lastMX = e.clientX;
    }
  });
  canvas.addEventListener('mouseleave', () => { mouseX = 0; });

  // Touch support
  let lastTX = 0;
  canvas.addEventListener('touchstart', (e) => { lastTX = e.touches[0].clientX; });
  canvas.addEventListener('touchmove', (e) => {
    e.preventDefault();
    targetRotY += (e.touches[0].clientX - lastTX) * 0.01;
    lastTX = e.touches[0].clientX;
  }, { passive: false });

  // ── ANIMATION ──
  const clock = new THREE.Clock();
  let autoRotSpeed = 0.003;

  function animate() {
    requestAnimationFrame(animate);
    const t = clock.getElapsedTime();

    if (model) {
      // Smooth rotation: auto-rotate + mouse influence
      const autoRot = t * autoRotSpeed;
      const mouseInfluence = mouseX * 0.6;
      currentRotY += (targetRotY + autoRot + mouseInfluence - currentRotY) * 0.06;
      model.rotation.y = currentRotY;

      // Model stays grounded
      model.position.y = -0.88;
    }

    // Particle drift
    const posAttr = pGeo.attributes.position;
    for (let i = 0; i < particleCount; i++) {
      posAttr.array[i * 3 + 1] += 0.0015;
      if (posAttr.array[i * 3 + 1] > 4) posAttr.array[i * 3 + 1] = -4;
    }
    posAttr.needsUpdate = true;

    // Sensor pulse
    sensors.forEach((s, i) => {
      if (!s.visible) return;
      const pulse = 0.85 + Math.sin(t * 2.8 + i * 0.5) * 0.15;
      s.scale.setScalar(pulse);
      let ringPulse = 1 + Math.sin(t * 2.0 + i * 0.3) * 0.4;
      // Make lower back ring (index 1) pulse larger by 15% more
      if (i === 1) ringPulse *= 1.725;
      rings[i].scale.setScalar(ringPulse);
      rings[i].material.opacity = 0.6 - Math.sin(t * 2.0 + i * 0.3) * 0.3;
      rings[i].lookAt(camera.position);
    });

    // Subtle camera bob
    camera.position.y = Math.sin(t * 0.4) * 0.04;

    composer.render();
  }

  animate();

  // ── RESIZE ──
  window.addEventListener('resize', () => {
    const s = getSize();
    camera.aspect = s.w / s.h;
    camera.updateProjectionMatrix();
    renderer.setSize(s.w, s.h);
    composer.setSize(s.w, s.h);
  });

})();

// ══════════════════════════════════════════════════════════════
// SIGNAL CANVAS - Live IMU waveform
// ══════════════════════════════════════════════════════════════
(function() {
  const canvas = document.getElementById('signal-canvas');
  if (!canvas) return;
  
  // Initial resize
  resizeCanvas(canvas);
  const ctx = canvas.getContext('2d');
  const parent = canvas.parentElement;

  const axes = [
    { color: '#30d158', freq: 1.1, amp: 38, phase: 0,    noise: 0.18 },
    { color: '#0a84ff', freq: 1.7, amp: 28, phase: 1.8,  noise: 0.12 },
    { color: '#bf5af2', freq: 2.3, amp: 20, phase: 3.4,  noise: 0.08 },
  ];

  let tSig = 0;
  const history = axes.map(() => []);
  let maxSamples = Math.max(1, Math.floor(canvas.getBoundingClientRect().width));

  // Function to reset the animation when patient changes
  window.resetSignalCanvas = function() {
    tSig = 0;
    history.forEach(arr => arr.length = 0);
    maxSamples = Math.max(1, Math.floor(canvas.getBoundingClientRect().width));
  };

  function drawSignal() {
    const rect = canvas.getBoundingClientRect();
    const drawW = rect.width;
    const drawH = rect.height;
    ctx.clearRect(0, 0, drawW, drawH);

    // Dark background
    ctx.fillStyle = '#1c1c1e';
    ctx.beginPath();
    ctx.roundRect(0, 0, drawW, drawH, 0);
    ctx.fill();

    // Axis baselines
    const baselines = [drawH * 0.22, drawH * 0.52, drawH * 0.80];

    axes.forEach(({ color, freq, amp, phase, noise }, ai) => {
      const base = baselines[ai];

      // Generate new sample
      const n = Math.sin(tSig * freq * 5.5 + phase) * amp
              + Math.sin(tSig * freq * 14 + phase * 1.7) * amp * 0.25
              + (Math.random() - 0.5) * amp * noise;
      history[ai].push(n);
      if (history[ai].length > maxSamples) history[ai].shift();

      const pts = history[ai];
      const xStep = drawW / maxSamples;

      // Area fill
      ctx.beginPath();
      ctx.moveTo(0, base);
      pts.forEach((v, i) => ctx.lineTo(i * xStep, base - v));
      ctx.lineTo((pts.length - 1) * xStep, base);
      ctx.closePath();
      const grad = ctx.createLinearGradient(0, base - amp, 0, base + amp);
      grad.addColorStop(0, color + '28');
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.fill();

      // Line
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 1.5;
      ctx.lineJoin = 'round';
      pts.forEach((v, i) => {
        const x = i * xStep;
        const y = base - v;
        i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
      });
      ctx.stroke();

      // Current value dot
      const lastX = (pts.length - 1) * xStep;
      const lastY = base - pts[pts.length - 1];
      ctx.beginPath();
      ctx.arc(lastX, lastY, 3.5, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();
      ctx.beginPath();
      ctx.arc(lastX, lastY, 7, 0, Math.PI * 2);
      ctx.strokeStyle = color + '55';
      ctx.lineWidth = 1;
      ctx.stroke();
    });

    // Dividers
    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 0.5;
    [drawH * 0.36, drawH * 0.67].forEach(y => {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(drawW, y); ctx.stroke();
    });

    tSig += 0.014;
    requestAnimationFrame(drawSignal);
  }
  
  drawSignal();

  // Handle window resize
  window.addEventListener('resize', () => {
    resizeCanvas(canvas);
    maxSamples = Math.max(1, Math.floor(canvas.getBoundingClientRect().width));
    // Reset history to match new width
    history.forEach(arr => arr.length = 0);
  });
})();

// ══════════════════════════════════════════════════════════════
// ANOMALY CANVAS - Score distribution
// ══════════════════════════════════════════════════════════════
(function() {
  const canvas = document.getElementById('anomaly-canvas');
  if (!canvas) return;
  resizeCanvas(canvas);
  const ctx = canvas.getContext('2d');

  const N = 90;
  let normalPts = [];
  let anomalyPts = [];
  let threshY = 0;

  function regenAnomalyData() {
    const rect = canvas.getBoundingClientRect();
    const W = rect.width;
    const H = rect.height;
    normalPts = Array.from({ length: N }, (_, i) => ({
      x: (i / N) * W,
      y: H * 0.55 + Math.sin(i * 0.28) * 22 + (Math.random() - 0.5) * 18
    }));
    anomalyPts = [
      { x: W * 0.13, y: H * 0.14 }, { x: W * 0.27, y: H * 0.09 },
      { x: W * 0.58, y: H * 0.17 }, { x: W * 0.74, y: H * 0.11 },
      { x: W * 0.89, y: H * 0.16 }
    ];
    threshY = H * 0.30;
  }

  regenAnomalyData();

  let tA = 0;
  function drawAnomaly() {
    const rect = canvas.getBoundingClientRect();
    const W = rect.width;
    const H = rect.height;
    ctx.clearRect(0, 0, W, H);

    // Threshold band
    ctx.fillStyle = 'rgba(255,255,255,0.03)';
    ctx.fillRect(0, 0, W, threshY);

    // Threshold line
    ctx.setLineDash([4, 4]);
    ctx.strokeStyle = 'rgba(255,255,255,0.18)';
    ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(0, threshY); ctx.lineTo(W, threshY); ctx.stroke();
    ctx.setLineDash([]);

    // Threshold label
    ctx.font = '10px -apple-system, sans-serif';
    ctx.fillStyle = 'rgba(255,255,255,0.25)';
    ctx.fillText('Detection threshold', 6, threshY - 6);

    // Normal signal area
    const areaGrad = ctx.createLinearGradient(0, H * 0.3, 0, H);
    areaGrad.addColorStop(0, 'rgba(48,209,88,0.12)');
    areaGrad.addColorStop(1, 'rgba(48,209,88,0.0)');
    ctx.beginPath();
    ctx.moveTo(0, H);
    normalPts.forEach(p => ctx.lineTo(p.x, p.y));
    ctx.lineTo(W, H);
    ctx.closePath();
    ctx.fillStyle = areaGrad;
    ctx.fill();

    // Normal line
    ctx.strokeStyle = '#30d158';
    ctx.lineWidth = 1.5;
    ctx.lineJoin = 'round';
    ctx.beginPath();
    normalPts.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
    ctx.stroke();

    // Normal dots
    ctx.fillStyle = '#30d158';
    normalPts.filter((_, i) => i % 12 === 0).forEach(p => {
      ctx.beginPath(); ctx.arc(p.x, p.y, 2.5, 0, Math.PI * 2); ctx.fill();
    });

    // Anomaly points
    anomalyPts.forEach((p, i) => {
      const pulse = 1 + Math.sin(tA * 2.5 + i * 1.3) * 0.3;

      // Outer ring
      ctx.beginPath();
      ctx.arc(p.x, p.y, 13 * pulse, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,69,58,0.08)';
      ctx.fill();

      // Mid ring
      ctx.beginPath();
      ctx.arc(p.x, p.y, 8, 0, Math.PI * 2);
      ctx.strokeStyle = 'rgba(255,69,58,0.35)';
      ctx.lineWidth = 1;
      ctx.stroke();

      // Core
      ctx.beginPath();
      ctx.arc(p.x, p.y, 4, 0, Math.PI * 2);
      ctx.fillStyle = '#ff453a';
      ctx.fill();

      // Vertical line to threshold
      ctx.setLineDash([2, 3]);
      ctx.strokeStyle = 'rgba(255,69,58,0.2)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(p.x, p.y + 4);
      ctx.lineTo(p.x, threshY);
      ctx.stroke();
      ctx.setLineDash([]);
    });

    tA += 0.016;
    requestAnimationFrame(drawAnomaly);
  }
  
  // Handle resize
  window.addEventListener('resize', () => {
    resizeCanvas(canvas);
    regenAnomalyData();
  });
  
  drawAnomaly();
})();

// ══════════════════════════════════════════════════════════════
// DEMO PATIENT SELECTION — results card
// ══════════════════════════════════════════════════════════════

const GRAPH_NAMES = [
  'Confidence',
  'Anomaly',
  'Cohort',
  'Trials'
];

// API_BASE can be configured via window.GAITGUARD_API_BASE or environment variable
// Defaults to localhost:8001 for development
const API_BASE = window.GAITGUARD_API_BASE || 'http://localhost:8001';
console.log('API_BASE set to:', API_BASE);

function createElement(tag, className, text) {
  const el = document.createElement(tag);
  if (className) el.className = className;
  if (text !== undefined) el.textContent = text;
  return el;
}

function renderMetaGrid(metaGrid, meta, anomaly) {
  if (!metaGrid) return;
  metaGrid.replaceChildren(
    createMetaCell('Confidence', meta.Confidence || '-'),
    createMetaCell('Anomaly', anomaly, anomaly === 'Detected' ? 'red' : ''),
    createMetaCell('Cohort', meta.Cohort || '-'),
    createMetaCell('Trials', meta.Trials || '-')
  );
}

function createMetaCell(label, value, valueClass) {
  const cell = createElement('div', 'meta-cell');
  cell.append(
    createElement('div', 'meta-key', label),
    createElement('div', ['meta-val', valueClass].filter(Boolean).join(' '), value)
  );
  return cell;
}

function setDropzoneState(icon, title, subtitle, options) {
  const dropzone = document.getElementById('dropzone');
  if (!dropzone) return;

  dropzone.replaceChildren(
    createElement('div', 'dz-icon', icon),
    createElement('div', 'dz-title', title),
    createElement('div', 'dz-sub', subtitle)
  );

  if (options && typeof options.onRetry === 'function') {
    const retryBtn = createElement('button', '', 'Try Again');
    retryBtn.style.marginTop = '12px';
    retryBtn.style.padding = '8px 16px';
    retryBtn.style.backgroundColor = 'var(--blue)';
    retryBtn.style.color = 'white';
    retryBtn.style.border = 'none';
    retryBtn.style.borderRadius = '6px';
    retryBtn.style.cursor = 'pointer';
    retryBtn.onclick = options.onRetry;
    dropzone.appendChild(retryBtn);
  }
}

function createTrialRow(result, riskClass, riskLevel, anomaly, graphValues, metaObj) {
  const row = createElement('div', 'trial-row active');
  row.dataset.score = result.risk_score || '-';
  row.dataset.risk = riskLevel;
  row.dataset.name = result.participant_id || 'Uploaded Patient';
  row.dataset.id = result.trial_id || 'Uploaded Trial';
  row.dataset.anomaly = anomaly;
  row.dataset.graph = JSON.stringify(graphValues);
  row.dataset.meta = JSON.stringify(metaObj);

  const left = createElement('div');
  left.append(
    createElement('div', 'trial-name', result.participant_id || 'Uploaded Patient'),
    createElement('div', 'trial-id', (result.trial_id || 'Uploaded Trial') + ' - Uploaded')
  );

  const pill = createElement('div', 'risk-pill ' + riskClass, riskLevel.toUpperCase());
  row.append(left, pill);
  return row;
}

// ── Render the result card from a row's data-* attributes ──
function renderCardFromRow(row) {
  return renderCardSafely(row);
}

function readRowData(row) {
  let graphValues = {};
  let meta = {};

  try { graphValues = JSON.parse(row.dataset.graph || '{}'); } catch (e) {}
  try { meta = JSON.parse(row.dataset.meta || '{}'); } catch (e) {}

  return {
    score: row.dataset.score || '-',
    risk: row.dataset.risk || 'low',
    name: row.dataset.name || '-',
    id: row.dataset.id || '-',
    anomaly: row.dataset.anomaly || 'Not Detected',
    graphValues,
    meta
  };
}

function renderCardSafely(row) {
  const data = readRowData(row);

  if (window.resetSignalCanvas) {
    window.resetSignalCanvas();
  }

  const rcName  = document.getElementById('rc-name');
  const rcSub   = document.getElementById('rc-sub');
  const rcScore = document.getElementById('rc-score');
  if (rcName)  rcName.textContent  = data.name;
  if (rcSub)   rcSub.textContent   = data.id + ' - ' + (data.anomaly === 'Detected' ? 'Anomaly Detected' : 'Normal');
  if (rcScore) {
    rcScore.textContent = data.score;
    rcScore.style.color =
      data.risk === 'high' ? 'var(--danger)'  :
      data.risk === 'mod'  ? 'var(--warning)' :
                             'var(--success)';
  }

  document.querySelectorAll('.shap-bar').forEach(function(bar, i) {
    const nameEl = bar.querySelector('.shap-name');
    const valEl  = bar.querySelector('.shap-val');
    const fillEl = bar.querySelector('.shap-fill');
    if (!nameEl || !valEl || !fillEl) return;

    const graphKey = GRAPH_NAMES[i].toLowerCase();
    const value = data.graphValues[graphKey] || 0;
    const pct = typeof value === 'number' ? value : (value ? Number(value) : 0);

    nameEl.textContent = GRAPH_NAMES[i] || ('Metric ' + (i + 1));
    valEl.textContent = Math.round(pct) + '%';
    fillEl.style.width = Math.max(0.5, pct) + '%';
    fillEl.classList.remove('fill-danger', 'fill-warn', 'fill-blue');
    if      (pct >= 70) fillEl.classList.add('fill-danger');
    else if (pct >= 40) fillEl.classList.add('fill-warn');
    else                fillEl.classList.add('fill-blue');
  });

  renderMetaGrid(document.getElementById('meta-grid'), data.meta, data.anomaly);
}

// ── Wire up click handlers using event delegation ──
function initTrialRows() {
  // Use the list container as the delegation target so it works
  // regardless of when rows were stamped into the DOM.
  const list = document.getElementById('trial-list')
             || document.querySelector('.trial-list')
             || document.body;

  list.addEventListener('click', function(e) {
    const row = e.target.closest('.trial-row');
    if (!row) return;

    // Toggle active
    document.querySelectorAll('.trial-row').forEach(function(r) {
      r.classList.remove('active');
    });
    row.classList.add('active');

    renderCardSafely(row);
  });

  // Initialise with whatever row is already active on load
  const active = document.querySelector('.trial-row.active');
  if (active) renderCardSafely(active);
}

// Run after the DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initTrialRows);
} else {
  initTrialRows();
}

// ── Public helper used by any "load patient X" buttons ──
function loadDemoPatient(patientId) {
  var rows = document.querySelectorAll('.trial-row');
  var target = null;
  rows.forEach(function(r) {
    if ((r.dataset.name || '').includes(patientId) ||
        (r.dataset.id   || '').includes(patientId)) {
      target = r;
    }
  });
  if (!target) { return; }
  rows.forEach(function(r) { r.classList.remove('active'); });
  target.classList.add('active');
  
  // Reset signal canvas when patient changes
  if (window.resetSignalCanvas) {
    window.resetSignalCanvas();
  }
  
  renderCardSafely(target);
  var results = document.getElementById('results');
  if (results) results.scrollIntoView({ behavior: 'smooth' });
}


// ══════════════════════════════════════════════════════════════
// FILE UPLOAD — dropzone + API call
// ══════════════════════════════════════════════════════════════

const dz = document.getElementById('dropzone');
const fileInput = document.createElement('input');
fileInput.type     = 'file';
fileInput.multiple = true;
fileInput.accept   = '.csv,.json,.zip';

function validateFiles(files) {
  const required = ['head_raw.csv', 'lower_back_raw.csv', 'left_foot_raw.csv', 'right_foot_raw.csv', 'metadata.json'];
  const names    = Array.from(files).map(function(f) { return f.name.toLowerCase(); });
  if (names.some(function(n) { return n.endsWith('.zip'); })) {
    return files.length === 1
      ? { valid: true, type: 'zip' }
      : { valid: false, error: 'Please upload only one ZIP file' };
  }
  const missing = required.filter(function(r) { return !names.includes(r); });
  return missing.length === 0
    ? { valid: true, type: 'individual' }
    : { valid: false, error: 'Missing files: ' + missing.join(', ') };
}

async function handleFiles(files) {
  return handleFilesSafe(files);
}

async function handleFilesSafe(files) {
  const fileList   = Array.from(files || []);
  const validation = validateFiles(fileList);
  if (!validation.valid) { alert(validation.error); return; }

  setDropzoneState('...', 'Processing...', 'Analysing gait patterns with ensemble models');

  try {
    const formData = new FormData();
    fileList.forEach(function(f) { formData.append('files', f); });

    let response;
    try {
      const url = (API_BASE || '') + '/predict';
      console.log('Fetching from:', url);
      response = await fetch(url, {
        method: 'POST',
        body: formData
      });
    } catch (error) {
      console.error('Fetch error:', error);
      throw new Error('Cannot connect to the API server. Please ensure the backend is running and reachable from this page.');
    }

    if (!response.ok) {
      let detail = 'API Error: ' + response.status + ' ' + response.statusText;
      try {
        const e = await response.json();
        detail = e.detail || e.message || detail;
      } catch (_) {}
      throw new Error(detail);
    }

    let result;
    try {
      result = await response.json();
    } catch (_) {
      throw new Error('Invalid response from API server');
    }

    setDropzoneState('Done', 'Analysis Complete!', 'Scroll down to see your fall risk report');
    injectApiResultSafe(result);
    setTimeout(function() {
      var r = document.getElementById('results');
      if (r) r.scrollIntoView({ behavior: 'smooth' });
    }, 1000);

  } catch (err) {
    const msg = (err && err.message) ? err.message : 'Unknown error. Please check your files and try again';
    setDropzoneState('Error', 'Upload Failed', msg, {
      onRetry: function() { window.location.reload(); }
    });
  }
}

// Inject an API result as a new trial row and render it
function injectApiResult(result) {
  return injectApiResultSafe(result);
}

function injectApiResultSafe(result) {
  const riskLevel = result.risk_level || 'low';
  const riskClass = riskLevel === 'high' ? 'r-high' : riskLevel === 'moderate' ? 'r-mod' : 'r-low';
  const anomaly   = result.anomaly_status || 'Not Detected';
  const graphValues = result.graph_values || {
    confidence: 0,
    anomaly: 20,
    cohort: 50,
    trials: 20
  };

  const metaObj = {
    Confidence: result.metadata && result.metadata.confidence ? result.metadata.confidence : '0%',
    Anomaly: result.metadata && result.metadata.anomaly ? result.metadata.anomaly : 'Normal',
    Cohort: (result.metadata && result.metadata.cohort) ? result.metadata.cohort : 'Uploaded',
    Trials: result.metadata && result.metadata.trials ? result.metadata.trials : '1'
  };

  if (window.resetSignalCanvas) {
    window.resetSignalCanvas();
  }

  const trialList = document.getElementById('trial-list');
  if (trialList) {
    document.querySelectorAll('.trial-row').forEach(function(r) { r.classList.remove('active'); });
    const row = createTrialRow(result, riskClass, riskLevel, anomaly, graphValues, metaObj);
    trialList.insertBefore(row, trialList.firstChild);
  }

  const activeRow = document.querySelector('.trial-row.active');
  if (activeRow) {
    renderCardSafely(activeRow);
  }
}

// ── Dropzone events ──
if (dz) {
  dz.addEventListener('dragover', function(e) {
    e.preventDefault();
    dz.style.borderColor = 'var(--blue)';
    dz.style.background  = 'var(--blue-light)';
  });
  dz.addEventListener('dragleave', function() {
    dz.style.borderColor = '';
    dz.style.background  = '';
  });
  dz.addEventListener('drop', function(e) {
    e.preventDefault();
    dz.style.borderColor = '';
    dz.style.background  = '';
    handleFilesSafe(e.dataTransfer.files);
  });
  dz.addEventListener('click', function(e) {
    e.preventDefault();
    fileInput.click();
  });
  fileInput.addEventListener('change', function(e) {
    if (e.target.files.length > 0) handleFilesSafe(e.target.files);
  });
}
